import styles from './AudioTrack.module.css';

function AudioTrack({ objects, clips, setClips }) {
    const sounds = [{
        red: '../data/sounds/red',
        green: '../data/sounds/green',
        blue: '../data/sounds/blue'
    }]

    function playClip() {
        const queueFigures = [
            'wait',
            'wait',
            'wait',
            'wait',
            'wait',
            'wait',
            'wait',
            'wait',
            'wait',
            'wait',
            'wait',
            'wait',
            'wait',
            'wait',
            'wait',
        ];
    }

    return (
        <div className={styles.audioTrack}>
            <button onClick={playClip}>..............</button>
            {Array.from({ length: 15 }, (_, i) => (
                <div
                    key={i}
                    className={styles.clip}
                    style={{
                        backgroundColor: objects.find(
                            (object) => object.queue === i + 1,
                        )?.color,
                    }}
                >
                    <div
                        className={styles.queue}
                        style={{
                            backgroundColor:
                                objects.find(
                                    (object) => object.queue === i + 1,
                                ) && '#1e1e1ebb',

                            borderRadius:
                                objects.find((object) => object.queue === i + 1)
                                    ?.radius === '50%'
                                    ? '100%'
                                    : '5%',
                        }}
                    >
                        <p>{i + 1}</p>
                    </div>
                </div>
            ))}
        </div>
    );
}

export default AudioTrack;
